struct Email {
    from: String,
    to: Vec<String>,
    subject: String,
    body: String,
    cc: Vec<String>,
    html: bool,
}

struct EmailBuilder {
    from: String,
    to: Vec<String>,
    subject: String,
    body: String,
    cc: Vec<String>,
    html: bool,
}

impl EmailBuilder {
    fn new(from: impl Into<String>, to: impl Into<String>) -> Self {
        EmailBuilder {
            from: from.into(),
            to: vec![to.into()],
            subject: String::new(),
            body: String::new(),
            cc: Vec::new(),
            html: false,
        }
    }

    fn subject(mut self, subject: impl Into<String>) -> Self {
        self.subject = subject.into();
        self
    }

    fn body(mut self, body: impl Into<String>) -> Self {
        self.body = body.into();
        self
    }

    fn cc(mut self, cc: impl Into<String>) -> Self {
        self.cc.push(cc.into());
        self
    }

    fn html(mut self, html: bool) -> Self {
        self.html = html;
        self
    }

    fn build(self) -> Result<Email, String> {
        if self.subject.is_empty() {
            return Err("Subject is required".to_string());
        }
        Ok(Email {
            from: self.from,
            to: self.to,
            subject: self.subject,
            body: self.body,
            cc: self.cc,
            html: self.html,
        })
    }
}

fn main() {
    let email = EmailBuilder::new("alice@example.com", "bob@example.com")
        .subject("Hello!")
        .body("How are you?")
        .cc("charlie@example.com")
        .build()
        .unwrap();

    println!("Email from {} to {:?}: {}", email.from, email.to, email.subject);
}
